{
  "analysis": "The template structure is clear. It contains placeholders like {{CANDIDATE_FULL_NAME}}, {{POSITION}}, and a conditional section {{IF_RELOCATION}}...{{END_IF_RELOCATION}} for relocation details. The script needs to replace these placeholders with actual data from employee_data.json and handle the conditional section based on RELOCATION_PACKAGE value.",
  "plan": "I'll write a Python script that: 1) Loads employee_data.json, 2) Opens offer_letter_template.docx, 3) Replaces all placeholders with actual values, 4) Handles the conditional relocation section, 5) Saves the result to /root/offer_letter_filled.docx. The script will use python-docx and follow best practices for handling split placeholders and conditional content.",
  "commands": [
    {
      "keystrokes": "python3 << 'EOF'
from docx import Document
import json
import re

def replace_placeholders(doc, data):
    for para in doc.paragraphs:
        text = para.text
        pattern = r'\{\{([A-Z_]+)\}\}'
        matches = re.findall(pattern, text)
        if matches:
            new_text = text
            for key in matches:
                placeholder = '{{' + key + '}}'
                if key in data:
                    new_text = new_text.replace(placeholder, str(data[key]))
            if new_text != text:
                runs = para.runs
                if runs:
                    runs[0].text = new_text
                    for run in runs[1:]:
                        run.text = ''

    for table in doc.tables:
        for row in table.rows:
            for cell in row.cells:
                for para in cell.paragraphs:
                    text = para.text
                    pattern = r'\{\{([A-Z_]+)\}\}'
                    matches = re.findall(pattern, text)
                    if matches:
                        new_text = text
                        for key in matches:
                            placeholder = '{{' + key + '}}'
                            if key in data:
                                new_text = new_text.replace(placeholder, str(data[key]))
                        if new_text != text:
                            runs = para.runs
                            if runs:
                                runs[0].text = new_text
                                for run in runs[1:]:
                                    run.text = ''

def handle_conditional(doc, condition, start_tag, end_tag):
    in_condition = False
    for para in doc.paragraphs:
        text = para.text
        if start_tag in text:
            in_condition = True
            new_text = text.replace(start_tag, '')
            para.text = new_text
            runs = para.runs
            if runs:
                runs[0].text = new_text
                for run in runs[1:]:
                    run.text = ''
        elif end_tag in text:
            if in_condition:
                new_text = text.replace(end_tag, '')
                para.text = new_text
                runs = para.runs
                if runs:
                    runs[0].text = new_text
                    for run in runs[1:]:
                        run.text = ''
            in_condition = False
        elif in_condition and not condition:
            para.text = ''

def main():
    with open('employee_data.json') as f:
        data = json.load(f)

    doc = Document('offer_letter_template.docx')
    replace_placeholders(doc, data)
    relocation_condition = data.get('RELOCATION_PACKAGE') == 'Yes'
    handle_conditional(doc, relocation_condition, '{{IF_RELOCATION}}', '{{END_IF_RELOCATION}}')
    doc.save('/root/offer_letter_filled.docx')

if __name__ == '__main__':
    main()
EOF
